function initReplace(txt,obj){
	for(var k in obj){		
		var key = line2Hump(k);
		//logger.info("==fileRead==|" + k + "|" + key + "|" + obj[k]);
		txt = txt.replaceAll("${"+key+"}", obj[k]);
	}
	return txt;
}

klog.info("一键导出数据处理时间开始:" + kutils.getNow("yyyy-MM-dd HH:mm:ss.SSS"));

var result = context.get('result');
result = result.substring(5); //去掉 file|
var filename = result.substring(0,result.indexOf("|"));
var fs = result.substring(result.indexOf("|") + 1);

var appData = JSON.parse(fs);


var versionType = "linux" ; //打包类型 linux或windows ,可能info值得到

var setupPath = "/data/" + versionType + "/"; //半成品安装包的路径
var pine = "k-pine"; //k-pine 目录名
var api = "/api/"; //api路径
var faas = "/faas/"; //faas路径

var application = api + "application.properties"; //application.properties 文件路径
var dbJson = api + "db.json"; //db.json 文件路径
var configJson = faas + "config.json"; //config.json 文件路径

var currDir = kutils.getCurrDirectory();
currDir += "/upload/";


var pine_new = pine + "-" + appData['info']['version'] + "-" + getDate() + "-" + getNowTime() ;

//复制k-pine目录 = k-pine-version-date-time
kutils.fileDelete(setupPath + pine_new); //删除
kutils.fileCopy(setupPath + pine, setupPath + pine_new); //复制

//生成pine文件 到 api 目录下
kutils.fileUpload(JSON.stringify(appData),setupPath + pine_new + api + filename,"GBK"); //写入

//读出 application.properties 文件，替换内容，再重新写入application.properties
var txt = kutils.fileRead(setupPath + pine_new + application );
txt = initReplace(txt,appData['info']); //替换
kutils.fileUpload(txt,setupPath + pine_new + application,"GBK");//写入

//读出 config.json 文件，替换内容，再重新写入config.json
txt = kutils.fileRead(setupPath + pine_new + configJson ); //读出
txt = initReplace(txt,appData['info']); //替换
kutils.fileUpload(txt,setupPath + pine_new + configJson,"GBK");//写入

//datasources 内容写入db.json
kutils.fileUpload(JSON.stringify(appData["datasources"]),setupPath + pine_new + dbJson,"GBK");//写入

//压缩k-pine.version.time目录为k-pine.version.time.zip,并读取zip包内容返回到前端
klog.info("开始压缩时间:" + kutils.getNow("yyyy-MM-dd HH:mm:ss.SSS"));
kutils.zip(setupPath + pine_new,setupPath + pine_new + ".zip","");
klog.info("完成压缩时间:" + kutils.getNow("yyyy-MM-dd HH:mm:ss.SSS"));
//移动目录到faas目录
kutils.fileMove(setupPath + pine_new + ".zip", currDir + pine_new + ".zip");

//txt = kutils.fileRead(setupPath + pine_new + ".zip"); 
//setResult('result', 'file|' + pine_new + ".zip" + "|" + txt);
setResult('result', pine_new + ".zip");

var applicationConfig = context.get('applicationConfig');
var exportData = context.get('exportData');
var export_data = {};
export_data["exportData"] = JSON.parse(exportData);
export_data["applicationConfig"] = JSON.parse(applicationConfig);

var data = {};
data["app_id"] = appData['info']['id'];
data["version"] = appData['info']['version'];
data["file_name"] = pine_new + ".zip";
data["export_data"] = JSON.stringify(export_data);
setResult('data', data);

//删除setupPath + pine_new目录
kutils.fileDelete(setupPath + pine_new); //删除

klog.info("一键导出数据处理时间结束:" + kutils.getNow("yyyy-MM-dd HH:mm:ss.SSS"));
